    public void DamageBase(int amount)
    {
        if (_isGameOver || amount <= 0)
        {
            return;
        }

        _currentBaseHealth = Mathf.Max(0, _currentBaseHealth - amount);
        RefreshHud();
        SetStatusMessage($"An enemy slipped through. Base lost {amount} HP.");

        if (_currentBaseHealth == 0)
        {
            ShowGameOver();
        }
    }

